+		// send handoff mail → respawn pane with fresh Claude instance.
+		"crew": {
+			PreCompact: []HookEntry{
+				{
+					Matcher: "",
+					Hooks: []Hook{
+						{
+							Type:    "command",
+							Command: fmt.Sprintf("%s && gt handoff --cycle --reason compaction", pathSetup),
+						},
+					},
+				},
+			},
+		},
+	}
 }

